<template><view class="page"><xy-header title="收货地址"/><view class="wrap"><view v-for="item in addresses" :key="item.addressId" class="card" @click="edit(item)"><view><text class="name">{{item.receiverName}} {{item.receiverMobile}}</text><text class="detail">{{item.province}}{{item.city}}{{item.district}}{{item.detail}}</text></view><text v-if="item.isDefault" class="default">默认</text></view><view v-if="!addresses.length" class="empty">暂无收货地址</view><button class="add" @click="edit()">新增收货地址</button></view><view v-if="editing" class="mask"><view class="dialog"><input v-model="form.receiverName" placeholder="收货人"/><input v-model="form.receiverMobile" placeholder="手机号"/><input v-model="form.province" placeholder="省"/><input v-model="form.city" placeholder="市"/><input v-model="form.district" placeholder="区县"/><input v-model="form.detail" placeholder="详细地址"/><label><checkbox :checked="form.isDefault" @click="form.isDefault=!form.isDefault"/>设为默认</label><view class="actions"><button @click="editing=false">取消</button><button class="save" @click="save">保存</button></view></view></view></view></template>
<script>
import { appRequest, ensureMemberSession, showRequestError } from '../../utils/api'
const blank=()=>({receiverName:'',receiverMobile:'',province:'',city:'',district:'',detail:'',isDefault:false})
export default{data(){return{addresses:[],editing:false,form:blank()}},onShow(){this.load()},methods:{async load(){try{await ensureMemberSession();this.addresses=await appRequest({url:'/app/addresses'})}catch(e){showRequestError(e)}},edit(item){this.form=item?{...item,isDefault:!!item.isDefault}:blank();this.editing=true},async save(){try{await appRequest({url:'/app/addresses',method:this.form.addressId?'PUT':'POST',data:this.form});this.editing=false;this.load()}catch(e){showRequestError(e)}}}}
</script>
<style scoped>.page{min-height:100vh;background:var(--xy-bg)}.wrap{padding:24rpx}.card{display:flex;justify-content:space-between;margin-bottom:18rpx;padding:28rpx;border-radius:20rpx;background:#fff}.name,.detail{display:block}.name{font-weight:700}.detail{margin-top:12rpx;color:var(--xy-ink-3);font-size:24rpx}.default{color:var(--xy-primary)}.empty{padding:100rpx;text-align:center;color:var(--xy-muted)}.add,.save{background:var(--xy-primary);color:#fff}.mask{position:fixed;inset:0;display:flex;align-items:center;padding:40rpx;background:rgba(0,0,0,.45)}.dialog{width:100%;padding:30rpx;border-radius:22rpx;background:#fff}.dialog input{margin-bottom:16rpx;padding:18rpx;background:var(--xy-surface-2)}.actions{display:flex;gap:18rpx;margin-top:24rpx}.actions button{flex:1}</style>
